scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  let rtnList = [];
  switch (disGubun) {
    case 1:
      rtnList = $c.gus.cfCommonPopUp($p, 'retrieveAcctDeptCdInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_bilgAcctDeptCd, txt_bilgAcctDeptNm);
      break;
    case 2:
      rtnList = $c.gus.cfCommonPopUp($p, 'retrieveAcctDeptCdInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_stockAcctDeptCd, txt_stockAcctDeptNm);
      break;
    case 3:
      rtnList = $c.gus.cfCommonPopUp($p, 'retrieveClntList', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_clntNo, txt_clntNm);
      break;
    case 4:
      rtnList = $c.gus.cfCommonPopUp($p, 'retrieveFmsOilStationInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_oilStatNo, txt_oilStaNm);
      break;
    case 5:
      rtnList = $c.gus.cfCommonPopUp($p, 'retrieveFmsOilStationInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_upperOilStrPlcNo, txt_upperOilStrPlcNm);
      break;
    case 6:
      rtnList = $c.gus.cfCommonPopUp($p, 'retrieveAcctDeptCdInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_pcostAcctDeptCd, txt_pcostAcctDeptNm);
      break;
    case 7:
      rtnList = $c.gus.cfCommonPopUp($p, 'retrieveClntList', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
      $c.gus.cfSetReturnValue($p, rtnList, ed_repClntNo, txt_repClntNm);
      break;
    default:
      break;
  }
};
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) {
    return;
  }
  $c.gus.cfClearPairObj($p, pairObj);
  let pVal = $c.gus.cfGetValue($p, inObj);
  if (isCode == null || isCode == true) {
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  } else {
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};
