scwin.ds_oilStatInfoTree_onloadcompleted = function (e) {
  let rowCnt = ds_oilStatInfoTree.getRowCount();
  if (rowCnt > 0) {
    tv_oilStatInfoTree.setFocus();
    tv_oilStatInfoTree.setNodePosition(parseInt(scwin.hid_tvIndex, 10) - 1);
    tv_oilStatInfoTree.expandNode(parseInt(scwin.hid_tvIndex, 10) - 1);
    scwin.isRetrieveTree = true;
  }
};
scwin.ds_oilStatInfoTree_onrowpositionchange = async function (info) {
  let row = ds_oilStatInfoTree.getRowPosition();
  if (row >= 0 && scwin.isRetrieveTree) {
    if (ds_oilStatInfoTree.getCellData(row, "oilOilStatNo") == "AAA") {
      scwin.f_ContentsDisable();
      ds_oilPch.removeAll();
      $c.gus.cfInitObjects($p, tbl_content);
    } else {
      scwin.f_getOilStatInfo(row);
      scwin.f_RetrieveOilStatInfo(row);
    }
    if (scwin.viewMode == "C" && ds_oilStatInfoTree.getRowStatus(scwin.createRow) == "C") {
      ds_oilStatInfoTree.removeRow(scwin.createRow);
    }
    $c.gus.cfDisableBtn($p, [b_Cancel2, b_Save2]);
    $c.gus.cfEnableObjects($p, [b_Create2, b_Update2]);
    scwin.viewMode = "S";
  }
};
scwin.ds_oilStatInfoTree_canrowpositionchange = async function (info) {
  let Row = info.row;
  if (scwin.preRow == Row) {
    scwin.preRow = -1;
    return false;
  }
  if (scwin.viewMode == "U" || scwin.viewMode == "C") {
    let chk = await $c.win.confirm($p, "현재 작업중 입니다. 취소 하시겠습니까?");
    if (!chk) {
      scwin.preRow = Row;
      return false;
    } else {
      return true;
    }
  }
};
